import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as i,c as e,d as r}from"./app-75fed8c6.js";const h={},l=r('<h2 id="概念" tabindex="-1"><a class="header-anchor" href="#概念" aria-hidden="true">#</a> 概念</h2><ul><li>【系统工程】是一种组织管理技术。</li><li>【系统工程】是为了最好的实现系统的母的，对系统的组成要素、组织结构、信息流、控制机构进行分析研究的科学方法。</li><li>【系统工程】从整体出发、从系统观念出发，以求【整体最有】。</li><li>【系统工程】利用计算机作为工具，对系统的结构、元素、信息和反馈等进行分析，以达到最优规划、最优设计、最优管理和最优控制的目的。</li><li>【系统工程方法】是一种现代的科学决策方法。</li></ul><h2 id="系统工程方法" tabindex="-1"><a class="header-anchor" href="#系统工程方法" aria-hidden="true">#</a> 系统工程方法</h2><h3 id="_1、霍尔三维结构-硬科学-方法论" tabindex="-1"><a class="header-anchor" href="#_1、霍尔三维结构-硬科学-方法论" aria-hidden="true">#</a> 1、霍尔三维结构 “硬科学”方法论</h3><h4 id="逻辑维-解决问题的逻辑过程" tabindex="-1"><a class="header-anchor" href="#逻辑维-解决问题的逻辑过程" aria-hidden="true">#</a> 逻辑维：解决问题的逻辑过程</h4><p>顺序：</p><ol><li>明确问题</li><li>确定目标 建立价值体系或评价体系</li><li>系统综合</li><li>系统分析</li><li>优化 系统方案的优化选择</li><li>系统决策</li><li>实施计划</li></ol><h4 id="时间维-工作进程" tabindex="-1"><a class="header-anchor" href="#时间维-工作进程" aria-hidden="true">#</a> 时间维：工作进程</h4><p>顺序：</p><ol><li>规划阶段 调研，谋求活动的规划与战略</li><li>拟定方案 提出具体的计划方案</li><li>研制阶段 完成研制方案及生产计划</li><li>生产阶段 生产零部件及提出安装计划</li><li>安装阶段 安装完毕，完成系统的运行计划</li><li>运行阶段 系统按照预期的用途开展服务</li><li>更新阶段 改进原有系统、或消亡原有系统</li></ol><h4 id="知识维-专业科学知识" tabindex="-1"><a class="header-anchor" href="#知识维-专业科学知识" aria-hidden="true">#</a> 知识维：专业科学知识</h4><p>工程、医药、建筑、商业、法律、管理</p><p>应用场景：组织和管理大型工程建设项目</p><h3 id="_2、切克兰德方法-软科学方法论" tabindex="-1"><a class="header-anchor" href="#_2、切克兰德方法-软科学方法论" aria-hidden="true">#</a> 2、切克兰德方法 “软科学方法论”</h3><p>核心不是“最优化”。而是“比较”和“探寻”</p><p>步骤：</p><p>认识问题、根底定义、建立概念模型、比较及探寻、选择、设计与实施、评估与反馈</p><h3 id="_3、并行工程方法" tabindex="-1"><a class="header-anchor" href="#_3、并行工程方法" aria-hidden="true">#</a> 3、并行工程方法</h3><p>“制造过程”与“支持过程”并行</p><p>强调三个方面：产品设计开发期间，最快速度按质完成；各项工作问题协调解决；适当的信息系统工具</p><h3 id="_4、综合集成法" tabindex="-1"><a class="header-anchor" href="#_4、综合集成法" aria-hidden="true">#</a> 4、综合集成法</h3><p>钱学森命名，【简单系统】和【巨系统】</p><p>四原则：整体论原则、相互联系原则、有序性原则、动态原则</p><h3 id="_5、wsr系统方法" tabindex="-1"><a class="header-anchor" href="#_5、wsr系统方法" aria-hidden="true">#</a> 5、WSR系统方法</h3><p>实践准则：【懂物理】【明事理】 【通人理】</p><h2 id="系统工程生命周期" tabindex="-1"><a class="header-anchor" href="#系统工程生命周期" aria-hidden="true">#</a> 系统工程生命周期</h2><h3 id="系统工程声明周期阶段" tabindex="-1"><a class="header-anchor" href="#系统工程声明周期阶段" aria-hidden="true">#</a> 系统工程声明周期阶段</h3><ol><li>探索性研究</li><li>概念阶段</li><li>开发阶段</li><li>生产阶段</li><li>使用阶段</li><li>保障阶段</li><li>退役阶段</li></ol><h3 id="系统工程声明周期方法" tabindex="-1"><a class="header-anchor" href="#系统工程声明周期方法" aria-hidden="true">#</a> 系统工程声明周期方法</h3><p>计划驱动方法：需求-》设计-》构建-》测试-》部署<br> 渐进迭代式开发：提供连续交付以达到期望的系统<br> 精益开发：起源于丰田，是一个动态的、知识驱动的，以客户为中心的过程、<br> 敏捷开发：更好的灵活性</p><h2 id="信息系统建设原则" tabindex="-1"><a class="header-anchor" href="#信息系统建设原则" aria-hidden="true">#</a> 信息系统建设原则</h2><ol><li>高层管理人员介入原则 如CIO介入</li><li>用户参与开发原则 用户确定范围、核心用户全程参与、用户深度参与</li><li>自顶向下规划原则 以此减少信息不一致的现象</li><li>工程化原则 引入【软件工程】</li><li>其他原则 创新性原则、整体性原则、发展性原则、经济性原则</li></ol><h2 id="信息系统开发方法" tabindex="-1"><a class="header-anchor" href="#信息系统开发方法" aria-hidden="true">#</a> 信息系统开发方法</h2><h3 id="结构化法" tabindex="-1"><a class="header-anchor" href="#结构化法" aria-hidden="true">#</a> 结构化法</h3><p>自顶向下，逐步分解求精</p><ol><li>开发目标清晰化</li><li>工作阶段程式化</li><li>开发文档规范化</li><li>设计方法结构化</li></ol><blockquote><p>应变能力差</p></blockquote><h3 id="面向对象法" tabindex="-1"><a class="header-anchor" href="#面向对象法" aria-hidden="true">#</a> 面向对象法</h3><ol><li>自底向上</li><li>阶段界限不明</li><li>更好应变、更好复用</li></ol><blockquote><p>符合人们的思维习惯</p></blockquote><h3 id="面向服务的方法" tabindex="-1"><a class="header-anchor" href="#面向服务的方法" aria-hidden="true">#</a> 面向服务的方法</h3><ol><li>粗粒度、松耦合</li><li>标准化和结构化</li></ol><p>抽象级别：操作【低】-》服务【中】-》业务流程【高】</p><h3 id="原型法【需求阶段】" tabindex="-1"><a class="header-anchor" href="#原型法【需求阶段】" aria-hidden="true">#</a> 原型法【需求阶段】</h3><p>针对需求不明确<br> 按功能分：水平原型（界面）、垂直原型（复杂算法）<br> 按最终结果分：抛弃式原型、演化式原型</p><h2 id="信息系统的分类" tabindex="-1"><a class="header-anchor" href="#信息系统的分类" aria-hidden="true">#</a> 信息系统的分类</h2><h3 id="业务处理系统【tps】" tabindex="-1"><a class="header-anchor" href="#业务处理系统【tps】" aria-hidden="true">#</a> 业务处理系统【TPS】</h3><p>早期最初级的信息系统【20世纪50-60年代】，又可称为电子数据处理系统，是计算机在管理方面早起应用的最初级形式的信息系统<br> 功能：数据输入、数据处理【批处理、OLTP】、数据库维护、文件报表产生<br> TPS是服务于组织管理层次中最底层、最基础的信息系统</p><p>数据处理</p><ul><li>批处理</li><li>联机实时处理</li></ul><h3 id="管理信息系统【mis】" tabindex="-1"><a class="header-anchor" href="#管理信息系统【mis】" aria-hidden="true">#</a> 管理信息系统【MIS】</h3><p>由业务处理系统发展而成的，是在TPS基础上引进大量管理方法对企业整体信息进行处理，并利用信息进行预测、控制、计划、辅助企业全面管理的信息系统<br> MIS系统四大部件：信息源、信息处理器、信息用户和信息管理者<br> 高度集成化的人机信息系统<br> 金字塔结构：分多个层级</p><h3 id="决策支持系统【dss】" tabindex="-1"><a class="header-anchor" href="#决策支持系统【dss】" aria-hidden="true">#</a> 决策支持系统【DSS】</h3><p>由语言系统、知识系统和问题处理系统3个互相关联的部分组成的，基于计算机的系统<br> 用于辅助决策、支持决策</p><p>DOSS应具有的特征</p><ul><li>数据和模型是DSS的主要资源</li><li>DSS用来支援用户作决策而不是代替用户作决策</li><li>DSS主要用于解决半结构化及非结构化问题</li><li>DSS的作用在于提高决策的有效性而不是提高决策的效率</li></ul><h3 id="专家系统【es】" tabindex="-1"><a class="header-anchor" href="#专家系统【es】" aria-hidden="true">#</a> 专家系统【ES】</h3><p>是一个智能计算机程序系统，其内部含有某个领域具有专家水平的大量知识与经验，能够利用人类专家的知识和解决问题的方法来处理该领域的问题<br> 知识+推理=专家系统。人工智能的一个重要分支</p><p>知识库：存储求解实际问题的领域知识<br> 综合数据库：存储问题的状态描述、中间结果、求解过程的记录等信息<br> 推理机：实质是【规则解释器】<br> 知识获取：两方面功能：知识的编辑求精及知识自学习<br> 解释程序：面向用户服务的</p><h3 id="办公自动化系统【oas】" tabindex="-1"><a class="header-anchor" href="#办公自动化系统【oas】" aria-hidden="true">#</a> 办公自动化系统【OAS】</h3><p>由计算机设备、办公设备、数据通信及网络设备、软件系统组成</p><h3 id="企业资源计划【erp】" tabindex="-1"><a class="header-anchor" href="#企业资源计划【erp】" aria-hidden="true">#</a> 企业资源计划【ERP】</h3><p>打通供应链，集成，整合</p>',63),d=[l];function n(s,t){return i(),e("div",null,d)}const p=a(h,[["render",n],["__file","01.系统工程与信息系统基础.html.vue"]]);export{p as default};
